// setup/install.js
const axios = require('axios');
const fs = require('fs');
const path = require('path');

async function downloadConfigFile(url, destination) {
  try {
    const response = await axios({
      method: 'get',
      url,
      responseType: 'stream'
    });

    return new Promise((resolve, reject) => {
      response.data.pipe(fs.createWriteStream(destination))
        .on('finish', resolve)
        .on('error', reject);
    });
  } catch (error) {
    console.error(`Failed to download ${url}:`, error);
    process.exit(1);
  }
}

async function setupGitHooks() {
  try {
    const hooksDir = path.resolve(__dirname, '../.git/hooks');
    if (!fs.existsSync(hooksDir)) {
      fs.mkdirSync(hooksDir);
    }

    const preCommitHookUrl = 'https://raw.githubusercontent.com/my-repo/pre-commit-hook/master/pre-commit';
    await downloadConfigFile(preCommitHookUrl, path.join(hooksDir, 'pre-commit'));
    fs.chmodSync(path.join(hooksDir, 'pre-commit'), 0o755);
  } catch (error) {
    console.error('Failed to set up git hooks:', error);
    process.exit(1);
  }
}

async function initializeProjectStructure() {
  try {
    const projectRoot = path.resolve(__dirname, '../');
    const configDir = path.join(projectRoot, 'config');

    if (!fs.existsSync(configDir)) {
      fs.mkdirSync(configDir);
    }

    const configFileUrl = 'https://raw.githubusercontent.com/my-repo/config-file/master/config.json';
    await downloadConfigFile(configFileUrl, path.join(configDir, 'config.json'));
  } catch (error) {
    console.error('Failed to initialize project structure:', error);
    process.exit(1);
  }
}

(async () => {
  try {
    await setupGitHooks();
    await initializeProjectStructure();
    console.log('Development environment set up successfully.');
  } catch (error) {
    console.error('Error during setup:', error);
    process.exit(1);
  }
})();